function getFadePercentage(weaponName, seed) {
  if (seed == null || !weaponName) return null;
  // Extract weapon name from market_hash_name like "★ Butterfly Knife | Fade (Factory New)"
  let weapon = weaponName.replace(/^★\s*/, '').replace(/\s*\|.*$/, '').replace(/^StatTrak™\s*/, '').trim();
  const key = FADE_DATA.map[weapon] || 'default';
  const arr = FADE_DATA[key];
  if (!arr || seed < 0 || seed >= arr.length) return null;
  return arr[seed];
}

function getBlueGemTier(weaponName, seed) {
  if (seed == null || !weaponName) return null;
  // Extract weapon from name
  let weapon = weaponName.replace(/^★\s*/, '').replace(/^StatTrak™\s*/, '').trim();
  weapon = weapon.split(' | ')[0].trim();
  const data = BLUE_GEM_DATA[weapon];
  if (!data) return null;
  if (data.scar && data.scar.includes(seed)) return 'Scar (#1)';
  if (data.t1 && data.t1.includes(seed)) return 'Tier 1';
  if (data.t2 && data.t2.includes(seed)) return 'Tier 2';
  if (data.t3 && data.t3.includes(seed)) return 'Tier 3';
  return null;
}

