function getPatternTier(weaponName, seed, paintindex) {
  if (seed == null || !weaponName) return null;
  var weapon = weaponName.replace(/^★\s*/, '').replace(/^StatTrak™\s*/, '').trim();
  weapon = weapon.split(' | ')[0].trim();
  var finish = weaponName.split(' | ')[1]?.split(' (')[0]?.trim() || '';

  // Doppler Phase 2 — Max Pink
  if (finish === 'Doppler' && paintindex === 419) {
    var pinkData = PATTERN_DATA.doppler_p2_pink[weapon];
    if (pinkData) {
      if (pinkData.t1?.includes(seed)) return {label:'Max Pink',tier:'T1',color:'#E91E8C'};
      if (pinkData.t2?.includes(seed)) return {label:'BTA Pink',tier:'T2',color:'#E91E8C'};
      if (pinkData.t3?.includes(seed)) return {label:'BTA Pink',tier:'T3',color:'#d67ab0'};
    }
  }
  // Doppler Phase 4 — Max Blue
  if (finish === 'Doppler' && paintindex === 421) {
    var blueData = PATTERN_DATA.doppler_p4_blue[weapon];
    if (blueData) {
      if (blueData.t1?.includes(seed)) return {label:'Max Blue',tier:'T1',color:'#3498DB'};
      if (blueData.t2?.includes(seed)) return {label:'BTA Blue',tier:'T2',color:'#5dade2'};
    }
  }
  // Marble Fade — Fire & Ice
  if (finish === 'Marble Fade') {
    var fiData = PATTERN_DATA.marble_fade_fi[weapon];
    if (fiData) {
      for (var tier of ['1st','2nd','3rd','4th','5th','6th','7th','8th','9th','10th']) {
        if (fiData[tier]?.includes(seed)) return {label:tier+' Max F&I',tier:tier,color:'#ff4444'};
      }
      if (fiData.fake?.includes(seed)) return {label:'Fake F&I',tier:'fake',color:'#ff8844'};
    }
  }
  // Crimson Web
  if (finish === 'Crimson Web') {
    var cwData = PATTERN_DATA.crimson_web[weapon];
    if (cwData) {
      if (cwData.double_web?.includes(seed)) return {label:'Double Web',tier:'T1',color:'#e74c3c'};
      if (cwData.centered_web?.includes(seed)) return {label:'Center Web',tier:'T2',color:'#e74c3c'};
      if (cwData.big_web?.includes(seed)) return {label:'Big Web',tier:'T2',color:'#e74c3c'};
      if (cwData.clean_corner?.includes(seed)) return {label:'Clean Corner',tier:'T3',color:'#c0392b'};
    }
  }
  return null;
}

